import{_ as e,c as a,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Token 統計: 成本監控與資料分析 | Antigravity-Manager","description":"學習 Token Stats 統計功能的使用方法。了解如何從響應提取 token 資料、按模型和帳號分析用量，透過 Top 列表定位最貴的模型與帳號，排查統計缺失問題。","frontmatter":{"title":"Token 統計: 成本監控與資料分析 | Antigravity-Manager","sidebarTitle":"一眼看穿誰最貴","subtitle":"Token 統計: 成本監控與資料分析","description":"學習 Token Stats 統計功能的使用方法。了解如何從響應提取 token 資料、按模型和帳號分析用量，透過 Top 列表定位最貴的模型與帳號，排查統計缺失問題。","tags":["Token Stats","成本","監控","SQLite","用量統計"],"prerequisite":["start-proxy-and-first-client","advanced-model-router"],"order":7},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"}'),d={name:"zh-tw/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"};function l(s,t,n,i,c,u){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="token-stats-成本視角的統計口徑與圖表解讀" tabindex="-1">Token Stats：成本視角的統計口徑與圖表解讀 <a class="header-anchor" href="#token-stats-成本視角的統計口徑與圖表解讀" aria-label="Permalink to &quot;Token Stats：成本視角的統計口徑與圖表解讀&quot;">​</a></h1><p>你已經把客戶端接進 Antigravity Tools 了，但「到底誰在燒錢、貴在哪、是不是某個模型突然飆了」通常很難靠直覺判斷。這一課只做一件事：把 Token Stats 頁裡的資料口徑講清楚，並教你用圖表快速定位成本問題。</p><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>說清楚 Token Stats 的資料來自哪裡（什麼時候會記錄、什麼情況下會缺失）</li><li>按小時/日/週切換觀察視窗，避免「只看一天」導致誤判</li><li>在「按模型/按帳號」兩種視圖下，用趨勢圖找異常峰值</li><li>用 Top 列表鎖定最貴模型/帳號，再回到請求日誌追根因</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><ul><li>你感覺調用變貴了，但不知道是模型變了、帳號變了，還是某天突然量大</li><li>你看到了 <code>X-Mapped-Model</code>，但不確定統計到底按哪個模型口徑算</li><li>Token Stats 裡偶爾是 0 或「暫無資料」，不知道是沒流量還是沒統計到</li></ul><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><ul><li>你要做成本優化：先把「誰最貴」量化出來</li><li>你在排查突發限流/異常：用峰值時間點去對照請求日誌</li><li>你在做模型路由/配額治理配置變動後，想驗證成本是否按預期下降</li></ul><h2 id="什麼是-token-stats" tabindex="-1">什麼是 Token Stats？ <a class="header-anchor" href="#什麼是-token-stats" aria-label="Permalink to &quot;什麼是 Token Stats？&quot;">​</a></h2><p><strong>Token Stats</strong>是 Antigravity Tools 的本地用量統計頁：代理在轉發請求後，會嘗試從響應 JSON 或流式資料中提取 <code>usage/usageMetadata</code> 裡的 token 數，並把每次請求按帳號與模型寫入本機 SQLite（<code>token_stats.db</code>），最後在 UI 裡按時間/模型/帳號彙總展示。</p><div class="info custom-block"><p class="custom-block-title">先說明一個容易踩的點</p><p>Token Stats 的「模型」口徑來自你請求裡的 <code>model</code> 欄位（或 Gemini 的 <code>/v1beta/models/&lt;model&gt;</code> 路徑解析），不等於路由後的 <code>X-Mapped-Model</code>。</p></div><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><ul><li>你已經跑通過一次代理調用（不會只停留在 <code>/healthz</code> 探活）</li><li>你的上游響應會返回可解析的 token 用量欄位（否則統計會缺失）</li></ul><div class="tip custom-block"><p class="custom-block-title">推薦搭配閱讀</p><p>如果你正在用模型映射把 <code>model</code> 路由到別的物理模型，建議先看 <strong><a href="/docs/opencodedocs/zh-tw/lbjlaq/Antigravity-Manager/advanced/model-router/">模型路由：自訂映射、萬用字元優先順序與預設策略</a></strong>，再回來看「統計口徑」會更直觀。</p></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Token Stats 的資料鏈路可以拆成三段：</p><ol><li>代理中介軟體嘗試從響應裡提取 token 用量（相容 <code>usage</code>/<code>usageMetadata</code>，流式也會解析）</li><li>如果同時拿到了 <code>account_email + input_tokens + output_tokens</code>，就寫入本機 SQLite（<code>token_stats.db</code>）</li><li>UI 透過 Tauri <code>invoke(get_token_stats_*)</code> 拉取聚合資料，按小時/日/週展示</li></ol><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-先確認你「有流量」" tabindex="-1">第 1 步：先確認你「有流量」 <a class="header-anchor" href="#第-1-步-先確認你「有流量」" aria-label="Permalink to &quot;第 1 步：先確認你「有流量」&quot;">​</a></h3><p><strong>為什麼</strong> Token Stats 統計來自真實請求。只啟動代理但沒發過一次模型請求，頁面就會顯示「暫無資料」。</p><p>做法：複用你在 <strong><a href="/docs/opencodedocs/zh-tw/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">啟動本地反代並接入第一個客戶端</a></strong> 裡已經驗證成功的那種調用方式，發 1-2 次請求。</p><p><strong>你應該看到</strong>：Token Stats 頁面從「載入中/暫無資料」變成有圖表或列表。</p><h3 id="第-2-步-選對時間視窗-小時-日-週" tabindex="-1">第 2 步：選對時間視窗（小時/日/週） <a class="header-anchor" href="#第-2-步-選對時間視窗-小時-日-週" aria-label="Permalink to &quot;第 2 步：選對時間視窗（小時/日/週）&quot;">​</a></h3><p><strong>為什麼</strong> 同一份資料在不同視窗下看到的「峰值/趨勢」完全不一樣。UI 裡三種視窗對應的取數範圍也不同：</p><ul><li>小時：最近 24 小時</li><li>日：最近 7 天</li><li>週：最近 4 週（趨勢視圖會按最近 30 天聚合）</li></ul><p><strong>你應該看到</strong>：切換後，趨勢圖橫軸粒度變化（小時顯示到「時」，日顯示到「月/日」，週顯示到「年-W週號」）。</p><h3 id="第-3-步-先看頂部總覽-確定「成本規模」" tabindex="-1">第 3 步：先看頂部總覽，確定「成本規模」 <a class="header-anchor" href="#第-3-步-先看頂部總覽-確定「成本規模」" aria-label="Permalink to &quot;第 3 步：先看頂部總覽，確定「成本規模」&quot;">​</a></h3><p><strong>為什麼</strong> 總覽卡片能先回答 3 個問題：總量大不大、輸入/輸出佔比是否異常、參與的帳號/模型是不是突然變多。</p><p>重點看這幾項：</p><ul><li>總 Token（<code>total_tokens</code>）</li><li>輸入/輸出 Token（<code>total_input_tokens</code> / <code>total_output_tokens</code>）</li><li>活躍帳號數（<code>unique_accounts</code>）</li><li>使用模型數（UI 直接用「分模型統計列表」的長度）</li></ul><p><strong>你應該看到</strong>：如果「活躍帳號數」突然飆高，通常意味著你在短時間內跑了更多帳號（例如切換到輪換策略）。</p><h3 id="第-4-步-用「分模型-分帳號使用趨勢」抓異常峰值" tabindex="-1">第 4 步：用「分模型/分帳號使用趨勢」抓異常峰值 <a class="header-anchor" href="#第-4-步-用「分模型-分帳號使用趨勢」抓異常峰值" aria-label="Permalink to &quot;第 4 步：用「分模型/分帳號使用趨勢」抓異常峰值&quot;">​</a></h3><p><strong>為什麼</strong> 趨勢圖是最適合抓「突然變貴」的入口。你不用先知道原因，先把「哪天/哪小時飆了」圈出來。</p><p>做法：</p><ol><li>在趨勢圖右上角切換「按模型 / 按帳號」</li><li>滑鼠懸停（Tooltip）看 Top 值，優先關注「突然衝到第一的那條」</li></ol><p><strong>你應該看到</strong>：</p><ul><li>按模型：某個模型在某個時間段突然抬升</li><li>按帳號：某個帳號在某個時間段突然抬升</li></ul><h3 id="第-5-步-用-top-列表把「最貴目標」鎖死" tabindex="-1">第 5 步：用 Top 列表把「最貴目標」鎖死 <a class="header-anchor" href="#第-5-步-用-top-列表把「最貴目標」鎖死" aria-label="Permalink to &quot;第 5 步：用 Top 列表把「最貴目標」鎖死&quot;">​</a></h3><p><strong>為什麼</strong> 趨勢圖告訴你「什麼時候異常」，Top 列表告訴你「誰最貴」。把這兩個交叉，就能快速定位排障範圍。</p><p>做法：</p><ul><li>在「按模型」視圖下，看「分模型詳細統計」表格的 <code>total_tokens / request_count / 佔比</code></li><li>在「按帳號」視圖下，看「帳號詳細統計」表格的 <code>total_tokens / request_count</code></li></ul><p><strong>你應該看到</strong>：最貴模型/帳號排在前面，且 <code>request_count</code> 能幫你區分「單次特別貴」還是「次數特別多」。</p><h3 id="第-6-步-可選-找到-token-stats-db-做備份-核對" tabindex="-1">第 6 步（可選）：找到 <code>token_stats.db</code>，做備份/核對 <a class="header-anchor" href="#第-6-步-可選-找到-token-stats-db-做備份-核對" aria-label="Permalink to &quot;第 6 步（可選）：找到 `token_stats.db`，做備份/核對&quot;">​</a></h3><p><strong>為什麼</strong> 當你懷疑「統計缺失」或想做離線分析時，直接拿 SQLite 檔案最靠譜。</p><p>做法：進入 Settings 的 Advanced 區域，點擊「打開資料目錄」，你會在資料目錄裡找到 <code>token_stats.db</code>。</p><p><strong>你應該看到</strong>：檔案列表裡有 <code>token_stats.db</code>（檔名由後端寫死）。</p><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><ul><li>你能說清楚 Token Stats 統計是「從響應裡的 usage/usageMetadata 提取後落到本地 SQLite」，不是雲端計費</li><li>你能在「按模型/按帳號」兩種趨勢視圖下，指出一個具體的峰值時間段</li><li>你能用 Top 列表給出一個可執行的排查結論：先查哪個模型或帳號</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><table tabindex="0"><thead><tr><th>現象</th><th>常見原因</th><th>你可以怎麼做</th></tr></thead><tbody><tr><td>Token Stats 顯示&quot;暫無資料&quot;</td><td>你確實沒產生模型請求；或上游響應沒帶可解析的 token 欄位</td><td>先複用已驗證可用的客戶端發請求；再看響應裡是否包含 <code>usage/usageMetadata</code></td></tr><tr><td>統計按&quot;模型&quot;看起來不對</td><td>統計口徑使用請求裡的 <code>model</code>，不是 <code>X-Mapped-Model</code></td><td>把模型路由當成&quot;請求模型 -&gt; 映射模型&quot;；統計看的是&quot;請求模型&quot;</td></tr><tr><td>帳號維度缺失</td><td>只有拿到 <code>X-Account-Email</code> 且解析到 token 用量時才會寫入</td><td>確認請求確實走到了帳號池；再對照請求日誌/響應標頭</td></tr><tr><td>啟用 Proxy Monitor 後統計資料偏大</td><td>當 Proxy Monitor 啟用時，每次請求的 token 會被記錄兩次</td><td>這已知的實作細節，不影響相對趨勢分析；如果需要精確值，可以暫時停用 Monitor 後重測</td></tr></tbody></table><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li>Token Stats 的核心價值是「把成本問題量化」，先定位，再優化</li><li>統計寫入時，帳號和 token 用量是必須的；模型缺失時會被記錄為 <code>&quot;unknown&quot;</code>（不會阻止寫入）</li><li>想做更精細的成本控制，下一步通常會回到模型路由或配額治理</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們解決長會話裡的「隱性穩定性問題」：<strong><a href="/docs/opencodedocs/zh-tw/lbjlaq/Antigravity-Manager/advanced/context-compression/">長會話穩定性：上下文壓縮、簽名快取與工具結果壓縮</a></strong>。</p></blockquote><p>你會學到：</p><ul><li>三層漸進式上下文壓縮分別在做什麼</li><li>為什麼「簽名快取」能減少 400 簽名錯誤</li><li>工具結果壓縮會刪掉什麼、保留什麼</li></ul><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Token Stats UI：時間視窗/視圖切換與取數</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L49-L166" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>49-166</td></tr><tr><td>Token Stats UI：空資料提示（&quot;暫無資料&quot;）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L458-L507" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>458-507</td></tr><tr><td>Token 用量提取：從請求解析 model、從響應解析 usage/usageMetadata</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L32-L120" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>32-120</td></tr><tr><td>Token 用量提取：流式與 JSON 響應解析 usage 欄位</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L122-L336" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>122-336</td></tr><tr><td>Token Stats 寫入點：拿到帳號+token 後寫入 SQLite</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L79-L136" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>79-136</td></tr><tr><td>資料庫檔名與表結構：<code>token_stats.db</code> / <code>token_usage</code> / <code>token_stats_hourly</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-126</td></tr><tr><td>寫入邏輯：<code>record_usage(account_email, model, input, output)</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L128-L159" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>128-159</td></tr><tr><td>查詢邏輯：小時/日/週、按帳號/按模型、趨勢與總覽</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L161-L555" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>161-555</td></tr><tr><td>Tauri 命令：<code>get_token_stats_*</code> 對前端暴露</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L791-L847" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>791-847</td></tr><tr><td>應用啟動時初始化 Token Stats DB</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L50-L56" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>50-56</td></tr><tr><td>設定頁：取得/打開資料目錄（用於找到 <code>token_stats.db</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L76-L143" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>76-143</td></tr></tbody></table></details>',59)])])}const g=e(d,[["render",l]]);export{b as __pageData,g as default};
